	/*bool*//*C bool C*/ function  calcCloseBreakEven()
	{
		/*Closing pricing points*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: on insert of a transaction into transaction*/
		/*	Use Case What: calcuate the closing position values*/
		/*	Use Case Why: so that checks can be made daily to advise that closing positions are hit*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//The price paid for the stock + transaction fee is the break even point.  
		//Since dollars is the final price, this is our break even price short of the sale transaction cost but we don't 
		//know what the transaction cost is so we have to go with this.
		$this->SetCloseBreakEven( $this->data['dollar'] / $this->data['numbershares'] );
