	{
		/*Closing pricing points*/
		/*This function is generated by the generator from codemeta_functions*/
		/*	Requirements:  0*/
		/*	Use Case Who: system*/
		/*	Use Case When: on insert of a transaction into transaction*/
		/*	Use Case What: calcuate the closing position values*/
		/*	Use Case Why: so that checks can be made daily to advise that closing positions are hit*/
		/*	Author: Kevin <fraser.ks@gmail.com>*/
		
		//The Closing Long strategy is selling the stock once a set percentage gain has been reached.
		$this->SetCloseLong( $this->data['dollar'] / $this->data['numbershares'] * (1 + ($percentageGain / 100) ) );
