		$this->calcClosePartial();
		$this->calcCloseTargetPrice();
		$this->calcCloseValueAtRisk();
		$this->InsertVAR();
		return TRUE;
		//If we don't have a return in the body in codemeta, return
		return FALSE;
	}
} /* class transaction_close */

